package channelgen

import (
	"bytes"
	"fmt"
	"go/format"
	"path/filepath"
	"strings"

	"github.com/shipq/shipq/codegen"
)

// GenerateE2ETest generates the Go source code for E2E plumbing tests
// that exercise each channel's full dispatch-to-stream pipeline using real
// infrastructure (Redis + Centrifugo). The generated file has a //go:build e2e
// build tag so it only runs when explicitly requested.
//
// The generated file is written to channels/spec/zz_generated_e2e_test.go.
func GenerateE2ETest(channels []codegen.SerializedChannelInfo, modulePath, shipqRoot string) error {
	code, err := GenerateE2ETestCode(channels, modulePath)
	if err != nil {
		return fmt.Errorf("generate e2e test code: %w", err)
	}

	specDir := filepath.Join(shipqRoot, "channels", "spec")
	if err := codegen.EnsureDir(specDir); err != nil {
		return fmt.Errorf("create channels/spec directory: %w", err)
	}

	outputPath := filepath.Join(specDir, "zz_generated_e2e_test.go")
	if _, err := codegen.WriteFileIfChanged(outputPath, code); err != nil {
		return fmt.Errorf("write e2e test file: %w", err)
	}

	return nil
}

// GenerateE2ETestCode generates the Go source code for E2E plumbing tests.
// Exported separately for unit testing the generator itself.
func GenerateE2ETestCode(channels []codegen.SerializedChannelInfo, modulePath string) ([]byte, error) {
	var buf bytes.Buffer

	// Classify channels
	type e2eMeta struct {
		ch                  codegen.SerializedChannelInfo
		dispatchMsg         *codegen.SerializedMessageInfo
		fromServerMsgs      []codegen.SerializedMessageInfo
		fromClientMidStream []codegen.SerializedMessageInfo
	}

	var metas []e2eMeta
	importSet := make(map[string]bool)

	for _, ch := range channels {
		var dispatch *codegen.SerializedMessageInfo
		var fromServer []codegen.SerializedMessageInfo
		var midStream []codegen.SerializedMessageInfo

		for i := range ch.Messages {
			msg := &ch.Messages[i]
			switch msg.Direction {
			case "server_to_client":
				fromServer = append(fromServer, *msg)
			case "client_to_server":
				if msg.IsDispatch {
					dispatch = msg
				} else {
					midStream = append(midStream, *msg)
				}
			}
		}

		if dispatch == nil {
			continue
		}

		metas = append(metas, e2eMeta{
			ch:                  ch,
			dispatchMsg:         dispatch,
			fromServerMsgs:      fromServer,
			fromClientMidStream: midStream,
		})

		if ch.PackagePath != "" {
			importSet[ch.PackagePath] = true
		}
	}

	if len(metas) == 0 {
		return []byte("//go:build e2e\n\n// Code generated by shipq. DO NOT EDIT.\npackage spec\n"), nil
	}

	// Collect all FromClient type names for echo filtering
	allFromClientTypes := make(map[string]bool)
	for _, m := range metas {
		if m.dispatchMsg != nil {
			allFromClientTypes[m.dispatchMsg.TypeName] = true
		}
		for _, mid := range m.fromClientMidStream {
			allFromClientTypes[mid.TypeName] = true
		}
	}

	// --- Build tag + file header ---
	buf.WriteString("//go:build e2e\n\n")
	buf.WriteString("// Code generated by shipq. DO NOT EDIT.\n")
	buf.WriteString("package spec\n\n")

	// --- Imports ---
	buf.WriteString("import (\n")
	buf.WriteString("\t\"bytes\"\n")
	buf.WriteString("\t\"context\"\n")
	buf.WriteString("\t\"encoding/json\"\n")
	buf.WriteString("\t\"fmt\"\n")
	buf.WriteString("\t\"io\"\n")
	buf.WriteString("\t\"net\"\n")
	buf.WriteString("\t\"net/http\"\n")
	buf.WriteString("\t\"testing\"\n")
	buf.WriteString("\t\"time\"\n")
	buf.WriteString("\n")

	configImport := modulePath + "/config"
	fmt.Fprintf(&buf, "\t%q\n", configImport)
	buf.WriteString("\n")

	// centrifuge-go client
	buf.WriteString("\t\"github.com/centrifugal/centrifuge-go\"\n")
	buf.WriteString("\n")

	// Channel packages
	seen := make(map[string]bool)
	for _, m := range metas {
		if m.ch.PackagePath != "" && !seen[m.ch.PackagePath] {
			seen[m.ch.PackagePath] = true
			fmt.Fprintf(&buf, "\t%s %q\n", m.ch.PackageName, m.ch.PackagePath)
		}
	}

	buf.WriteString(")\n\n")

	// Suppress unused import warnings
	buf.WriteString("// Ensure imports are used.\n")
	buf.WriteString("var _ = context.Background\n")
	buf.WriteString("var _ = config.Settings\n")
	buf.WriteString("var _ = fmt.Sprintf\n")
	buf.WriteString("var _ = time.Second\n")
	buf.WriteString("var _ = bytes.NewReader\n")
	buf.WriteString("var _ = io.Discard\n")
	buf.WriteString("var _ = net.Dial\n")
	buf.WriteString("var _ = http.StatusOK\n")
	buf.WriteString("var _ = json.Marshal\n")
	buf.WriteString("var _ = centrifuge.NewJsonClient\n")
	for _, m := range metas {
		if m.ch.PackagePath != "" {
			fmt.Fprintf(&buf, "var _ = %s.Register\n", m.ch.PackageName)
			break // just need one to suppress
		}
	}
	buf.WriteString("\n")

	// --- envelope type ---
	generateE2EEnvelopeType(&buf)

	// --- Helper: pingRedis ---
	generatePingRedis(&buf)

	// --- Helper: pingCentrifugo ---
	// [L8]: Uses POST /api/info, NOT /health
	generatePingCentrifugo(&buf)

	// --- Helper: dispatchJob ---
	generateDispatchJob(&buf)

	// --- Helper: getTokens ---
	generateGetTokens(&buf)

	// --- Helper: connectAndSubscribe ---
	// [L6]: buffered channel capacity 64+, non-blocking send in OnPublication
	// [L7]: cleanup uses client.Close() (terminal), not Disconnect()
	generateConnectAndSubscribe(&buf)

	// --- Helper: isFromClientType ---
	generateIsFromClientType(&buf, allFromClientTypes)

	// --- Main test function ---
	fmt.Fprintf(&buf, "func TestE2E_WorkerPipeline(t *testing.T) {\n")
	buf.WriteString("\t// Skip if infrastructure is not available\n")
	buf.WriteString("\tredisURL := config.Settings.REDIS_URL\n")
	buf.WriteString("\tif redisURL == \"\" {\n")
	buf.WriteString("\t\tredisURL = \"redis://localhost:6379\"\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tif err := pingRedis(redisURL); err != nil {\n")
	buf.WriteString("\t\tt.Skipf(\"Redis not reachable at %s: %v\", redisURL, err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\n")
	buf.WriteString("\tapiURL := config.Settings.CENTRIFUGO_API_URL\n")
	buf.WriteString("\tif apiURL == \"\" {\n")
	buf.WriteString("\t\tapiURL = \"http://localhost:8000/api\"\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tapiKey := config.Settings.CENTRIFUGO_API_KEY\n")
	buf.WriteString("\tif err := pingCentrifugo(apiURL, apiKey); err != nil {\n")
	buf.WriteString("\t\tt.Skipf(\"Centrifugo not reachable at %s: %v\", apiURL, err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\n")
	buf.WriteString("\tbaseURL := fmt.Sprintf(\"http://localhost:%s\", config.Settings.PORT)\n")
	buf.WriteString("\n")

	// Generate subtests per channel
	for _, m := range metas {
		generateE2ESubtest(&buf, m.ch, m.dispatchMsg, m.fromServerMsgs, m.fromClientMidStream)
	}

	buf.WriteString("}\n")

	formatted, err := format.Source(buf.Bytes())
	if err != nil {
		// Return unformatted for debugging
		return buf.Bytes(), fmt.Errorf("format e2e test code: %w\nunformatted:\n%s", err, buf.String())
	}

	return formatted, nil
}

// generateE2EEnvelopeType writes a local envelope type for message parsing.
func generateE2EEnvelopeType(buf *bytes.Buffer) {
	buf.WriteString("// e2eEnvelope is the wire format used by the channel runtime.\n")
	buf.WriteString("type e2eEnvelope struct {\n")
	buf.WriteString("\tType string          `json:\"type\"`\n")
	buf.WriteString("\tData json.RawMessage `json:\"data\"`\n")
	buf.WriteString("}\n\n")
}

// generatePingRedis writes a helper that checks Redis reachability via raw TCP.
// [L8]: Uses raw TCP dial + PING/PONG exchange (proven pattern from Chunk 0).
func generatePingRedis(buf *bytes.Buffer) {
	buf.WriteString("// pingRedis attempts a raw TCP PING/PONG exchange with Redis.\n")
	buf.WriteString("func pingRedis(redisURL string) error {\n")
	buf.WriteString("\t// Extract host:port from redis URL\n")
	buf.WriteString("\taddr := redisURL\n")
	buf.WriteString("\tif len(addr) > 8 && addr[:8] == \"redis://\" {\n")
	buf.WriteString("\t\taddr = addr[8:]\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\t// Strip path (e.g., /0)\n")
	buf.WriteString("\tfor i := 0; i < len(addr); i++ {\n")
	buf.WriteString("\t\tif addr[i] == '/' {\n")
	buf.WriteString("\t\t\taddr = addr[:i]\n")
	buf.WriteString("\t\t\tbreak\n")
	buf.WriteString("\t\t}\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tif addr == \"\" {\n")
	buf.WriteString("\t\taddr = \"localhost:6379\"\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\n")
	buf.WriteString("\tconn, err := net.DialTimeout(\"tcp\", addr, 2*time.Second)\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn fmt.Errorf(\"dial redis %s: %w\", addr, err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tdefer conn.Close()\n")
	buf.WriteString("\n")
	buf.WriteString("\t_ = conn.SetDeadline(time.Now().Add(2 * time.Second))\n")
	buf.WriteString("\t_, err = conn.Write([]byte(\"PING\\r\\n\"))\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn fmt.Errorf(\"write PING: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\n")
	buf.WriteString("\trespBuf := make([]byte, 64)\n")
	buf.WriteString("\tn, err := conn.Read(respBuf)\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn fmt.Errorf(\"read PONG: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tif string(respBuf[:n]) != \"+PONG\\r\\n\" {\n")
	buf.WriteString("\t\treturn fmt.Errorf(\"unexpected response: %q\", string(respBuf[:n]))\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treturn nil\n")
	buf.WriteString("}\n\n")
}

// generatePingCentrifugo writes a helper that checks Centrifugo reachability.
// [L8]: Centrifugo v6 has NO /health endpoint; POST /api/info is the correct liveness check.
func generatePingCentrifugo(buf *bytes.Buffer) {
	buf.WriteString("// pingCentrifugo checks Centrifugo liveness via POST /api/info.\n")
	buf.WriteString("// [L8]: Centrifugo v6 has NO /health endpoint. Use POST /api/info.\n")
	buf.WriteString("func pingCentrifugo(apiURL, apiKey string) error {\n")
	buf.WriteString("\tclient := &http.Client{Timeout: 2 * time.Second}\n")
	buf.WriteString("\tinfoURL := apiURL\n")
	buf.WriteString("\tif !isStringSuffixed(infoURL, \"/info\") {\n")
	buf.WriteString("\t\t// Trim trailing slash and append /info\n")
	buf.WriteString("\t\tfor len(infoURL) > 0 && infoURL[len(infoURL)-1] == '/' {\n")
	buf.WriteString("\t\t\tinfoURL = infoURL[:len(infoURL)-1]\n")
	buf.WriteString("\t\t}\n")
	buf.WriteString("\t\tinfoURL = infoURL + \"/info\"\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treq, err := http.NewRequest(\"POST\", infoURL, bytes.NewReader([]byte(`{}`)))\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn fmt.Errorf(\"create request: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treq.Header.Set(\"X-API-Key\", apiKey)\n")
	buf.WriteString("\treq.Header.Set(\"Content-Type\", \"application/json\")\n")
	buf.WriteString("\tresp, err := client.Do(req)\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn fmt.Errorf(\"POST %s: %w\", infoURL, err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tdefer resp.Body.Close()\n")
	buf.WriteString("\t_, _ = io.Copy(io.Discard, resp.Body)\n")
	buf.WriteString("\tif resp.StatusCode != http.StatusOK {\n")
	buf.WriteString("\t\treturn fmt.Errorf(\"POST %s returned status %d\", infoURL, resp.StatusCode)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treturn nil\n")
	buf.WriteString("}\n\n")

	// Helper for string suffix check without importing strings
	buf.WriteString("func isStringSuffixed(s, suffix string) bool {\n")
	buf.WriteString("\tif len(s) < len(suffix) {\n")
	buf.WriteString("\t\treturn false\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treturn s[len(s)-len(suffix):] == suffix\n")
	buf.WriteString("}\n\n")
}

// generateDispatchJob writes a helper that dispatches a job via HTTP POST.
func generateDispatchJob(buf *bytes.Buffer) {
	buf.WriteString("// dispatchJob POSTs to the dispatch endpoint and returns the job_id.\n")
	buf.WriteString("func dispatchJob(baseURL, channelName string, payload any) (string, error) {\n")
	buf.WriteString("\tdata, err := json.Marshal(payload)\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn \"\", fmt.Errorf(\"marshal payload: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\turl := fmt.Sprintf(\"%s/channels/%s/dispatch\", baseURL, channelName)\n")
	buf.WriteString("\tresp, err := http.Post(url, \"application/json\", bytes.NewReader(data))\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn \"\", fmt.Errorf(\"POST %s: %w\", url, err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tdefer resp.Body.Close()\n")
	buf.WriteString("\tbody, _ := io.ReadAll(resp.Body)\n")
	buf.WriteString("\tif resp.StatusCode != http.StatusAccepted {\n")
	buf.WriteString("\t\treturn \"\", fmt.Errorf(\"POST %s returned %d: %s\", url, resp.StatusCode, string(body))\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tvar result struct{ JobID string `json:\"job_id\"` }\n")
	buf.WriteString("\tif err := json.Unmarshal(body, &result); err != nil {\n")
	buf.WriteString("\t\treturn \"\", fmt.Errorf(\"decode response: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treturn result.JobID, nil\n")
	buf.WriteString("}\n\n")
}

// generateGetTokens writes a helper that fetches connection + subscription tokens.
func generateGetTokens(buf *bytes.Buffer) {
	buf.WriteString("// e2eTokens holds the tokens returned by the token endpoint.\n")
	buf.WriteString("type e2eTokens struct {\n")
	buf.WriteString("\tConnToken string `json:\"connection_token\"`\n")
	buf.WriteString("\tSubToken  string `json:\"subscription_token\"`\n")
	buf.WriteString("\tChannel   string `json:\"channel\"`\n")
	buf.WriteString("\tWsURL     string `json:\"ws_url\"`\n")
	buf.WriteString("}\n\n")

	buf.WriteString("// getTokens fetches connection + subscription tokens for a dispatched job.\n")
	buf.WriteString("func getTokens(baseURL, channelName, jobID string) (e2eTokens, error) {\n")
	buf.WriteString("\turl := fmt.Sprintf(\"%s/channels/%s/tokens?job_id=%s\", baseURL, channelName, jobID)\n")
	buf.WriteString("\tresp, err := http.Get(url)\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn e2eTokens{}, fmt.Errorf(\"GET %s: %w\", url, err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tdefer resp.Body.Close()\n")
	buf.WriteString("\tbody, _ := io.ReadAll(resp.Body)\n")
	buf.WriteString("\tif resp.StatusCode != http.StatusOK {\n")
	buf.WriteString("\t\treturn e2eTokens{}, fmt.Errorf(\"GET %s returned %d: %s\", url, resp.StatusCode, string(body))\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\tvar tok e2eTokens\n")
	buf.WriteString("\tif err := json.Unmarshal(body, &tok); err != nil {\n")
	buf.WriteString("\t\treturn e2eTokens{}, fmt.Errorf(\"decode tokens: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treturn tok, nil\n")
	buf.WriteString("}\n\n")
}

// generateConnectAndSubscribe writes a helper that connects to Centrifugo and
// subscribes to a channel via centrifuge-go.
// [L6] Critical: OnPublication callback uses non-blocking send to a buffered Go
//
//	channel (capacity 64+). Blocking inside OnPublication deadlocks the
//	centrifuge-go read loop.
//
// [L7]: Cleanup uses client.Close() (terminal state), not Disconnect().
func generateConnectAndSubscribe(buf *bytes.Buffer) {
	buf.WriteString("// connectAndSubscribe creates a centrifuge-go client, connects with the\n")
	buf.WriteString("// connection token, subscribes to the channel with the subscription token,\n")
	buf.WriteString("// and returns handles for sending/receiving and cleanup.\n")
	buf.WriteString("// [L6]: OnPublication uses a buffered channel (cap 128) with non-blocking send.\n")
	buf.WriteString("// [L7]: Cleanup calls client.Close() (terminal), not Disconnect().\n")
	buf.WriteString("func connectAndSubscribe(wsURL, connToken, subToken, channelName string) (\n")
	buf.WriteString("\tclient *centrifuge.Client,\n")
	buf.WriteString("\tsub *centrifuge.Subscription,\n")
	buf.WriteString("\tpubCh <-chan []byte,\n")
	buf.WriteString("\terr error,\n")
	buf.WriteString(") {\n")
	buf.WriteString("\tclient = centrifuge.NewJsonClient(wsURL, centrifuge.Config{\n")
	buf.WriteString("\t\tToken: connToken,\n")
	buf.WriteString("\t})\n")
	buf.WriteString("\n")
	buf.WriteString("\tif err = client.Connect(); err != nil {\n")
	buf.WriteString("\t\treturn nil, nil, nil, fmt.Errorf(\"connect: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\n")
	buf.WriteString("\t// [L6]: Buffered channel with capacity 128 for non-blocking OnPublication.\n")
	buf.WriteString("\tmsgCh := make(chan []byte, 128)\n")
	buf.WriteString("\n")
	buf.WriteString("\tsub, err = client.NewSubscription(channelName, centrifuge.SubscriptionConfig{\n")
	buf.WriteString("\t\tGetToken: func(e centrifuge.SubscriptionTokenEvent) (string, error) {\n")
	buf.WriteString("\t\t\treturn subToken, nil\n")
	buf.WriteString("\t\t},\n")
	buf.WriteString("\t})\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\tclient.Close()\n")
	buf.WriteString("\t\treturn nil, nil, nil, fmt.Errorf(\"new subscription: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\n")
	buf.WriteString("\tsub.OnPublication(func(e centrifuge.PublicationEvent) {\n")
	buf.WriteString("\t\t// [L6] CRITICAL: Non-blocking send. If the channel is full, drop the\n")
	buf.WriteString("\t\t// message rather than deadlocking the centrifuge-go read loop.\n")
	buf.WriteString("\t\tselect {\n")
	buf.WriteString("\t\tcase msgCh <- e.Data:\n")
	buf.WriteString("\t\tdefault:\n")
	buf.WriteString("\t\t\t// Drop message if buffer is full.\n")
	buf.WriteString("\t\t}\n")
	buf.WriteString("\t})\n")
	buf.WriteString("\n")
	buf.WriteString("\tif err = sub.Subscribe(); err != nil {\n")
	buf.WriteString("\t\tclient.Close()\n")
	buf.WriteString("\t\treturn nil, nil, nil, fmt.Errorf(\"subscribe: %w\", err)\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\n")
	buf.WriteString("\treturn client, sub, msgCh, nil\n")
	buf.WriteString("}\n\n")
}

// generateIsFromClientType writes a helper that checks if a type name is a
// known FromClient type, for echo filtering in bidirectional channel tests.
// [L1]: After sub.Publish(), the test client receives its own message echoed back.
func generateIsFromClientType(buf *bytes.Buffer, allFromClientTypes map[string]bool) {
	buf.WriteString("// isFromClientType returns true if typeName is a known FromClient message type.\n")
	buf.WriteString("// Used for echo filtering in bidirectional channel tests.\n")
	buf.WriteString("// [L1]: Centrifugo echoes client-side publishes to all subscribers including the publisher.\n")
	buf.WriteString("func isFromClientType(typeName string) bool {\n")
	buf.WriteString("\tswitch typeName {\n")
	buf.WriteString("\tcase\n")
	i := 0
	for typeName := range allFromClientTypes {
		if i > 0 {
			buf.WriteString(",\n")
		}
		fmt.Fprintf(buf, "\t\t%q", typeName)
		i++
	}
	buf.WriteString(":\n")
	buf.WriteString("\t\treturn true\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treturn false\n")
	buf.WriteString("}\n\n")
}

// generateE2ESubtest writes a t.Run sub-test for a single channel.
func generateE2ESubtest(buf *bytes.Buffer, ch codegen.SerializedChannelInfo, dispatchMsg *codegen.SerializedMessageInfo, fromServerMsgs []codegen.SerializedMessageInfo, fromClientMidStream []codegen.SerializedMessageInfo) {
	hasMidStream := len(fromClientMidStream) > 0

	fmt.Fprintf(buf, "\tt.Run(%q, func(t *testing.T) {\n", ch.Name)

	// --- Step 1: Dispatch a job ---
	dispatchType := ch.PackageName + "." + dispatchMsg.TypeName
	fmt.Fprintf(buf, "\t\t// Dispatch a job for channel %q\n", ch.Name)
	fmt.Fprintf(buf, "\t\treq := %s{", dispatchType)
	writeE2ETestFieldValues(buf, dispatchMsg.Fields)
	buf.WriteString("}\n")
	fmt.Fprintf(buf, "\t\tjobID, err := dispatchJob(baseURL, %q, req)\n", ch.Name)
	buf.WriteString("\t\tif err != nil {\n")
	buf.WriteString("\t\t\tt.Fatalf(\"dispatchJob: %v\", err)\n")
	buf.WriteString("\t\t}\n")
	buf.WriteString("\t\tt.Logf(\"dispatched job: %s\", jobID)\n")
	buf.WriteString("\n")

	// --- Step 2: Get tokens ---
	fmt.Fprintf(buf, "\t\ttok, err := getTokens(baseURL, %q, jobID)\n", ch.Name)
	buf.WriteString("\t\tif err != nil {\n")
	buf.WriteString("\t\t\tt.Fatalf(\"getTokens: %v\", err)\n")
	buf.WriteString("\t\t}\n")
	buf.WriteString("\n")

	// --- Step 3: Connect and subscribe ---
	buf.WriteString("\t\tclient, sub, pubCh, err := connectAndSubscribe(tok.WsURL, tok.ConnToken, tok.SubToken, tok.Channel)\n")
	buf.WriteString("\t\tif err != nil {\n")
	buf.WriteString("\t\t\tt.Fatalf(\"connectAndSubscribe: %v\", err)\n")
	buf.WriteString("\t\t}\n")
	buf.WriteString("\t\t// [L7]: Use Close() (terminal), not Disconnect().\n")
	buf.WriteString("\t\tdefer client.Close()\n")
	buf.WriteString("\t\tdefer sub.Unsubscribe()\n")
	buf.WriteString("\n")

	// --- Step 4: Collect messages ---
	buf.WriteString("\t\t// Collect messages with a timeout\n")
	buf.WriteString("\t\ttimeout := 30 * time.Second\n")
	buf.WriteString("\t\tdeadline := time.After(timeout)\n")
	buf.WriteString("\t\tvar received []e2eEnvelope\n")
	buf.WriteString("\n")

	if !hasMidStream {
		// Unidirectional: just collect all expected FromServer messages
		expectedCount := len(fromServerMsgs)
		fmt.Fprintf(buf, "\t\texpectedCount := %d\n", expectedCount)
		buf.WriteString("\tcollectLoop:\n")
		buf.WriteString("\t\tfor len(received) < expectedCount {\n")
		buf.WriteString("\t\t\tselect {\n")
		buf.WriteString("\t\t\tcase <-deadline:\n")
		buf.WriteString("\t\t\t\tt.Fatalf(\"timed out after %v waiting for messages; received %d of %d: %+v\", timeout, len(received), expectedCount, received)\n")
		buf.WriteString("\t\t\tcase data := <-pubCh:\n")
		buf.WriteString("\t\t\t\tvar env e2eEnvelope\n")
		buf.WriteString("\t\t\t\tif err := json.Unmarshal(data, &env); err != nil {\n")
		buf.WriteString("\t\t\t\tt.Logf(\"skip unparseable message: %s\", string(data))\n")
		buf.WriteString("\t\t\t\t\tcontinue\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t\t// Skip echoed FromClient messages\n")
		buf.WriteString("\t\t\t\tif isFromClientType(env.Type) {\n")
		buf.WriteString("\t\t\t\t\tcontinue\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t\treceived = append(received, env)\n")
		buf.WriteString("\t\t\t\tif len(received) >= expectedCount {\n")
		buf.WriteString("\t\t\t\t\tbreak collectLoop\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t}\n")
		buf.WriteString("\t\t}\n")
		buf.WriteString("\n")

		// Verify each expected type was received
		buf.WriteString("\t\t// Verify expected FromServer messages\n")
		buf.WriteString("\t\treceivedTypes := make(map[string]int)\n")
		buf.WriteString("\t\tfor _, env := range received {\n")
		buf.WriteString("\t\t\treceivedTypes[env.Type]++\n")
		buf.WriteString("\t\t}\n")
		for _, srv := range fromServerMsgs {
			fmt.Fprintf(buf, "\t\tif receivedTypes[%q] == 0 {\n", srv.TypeName)
			fmt.Fprintf(buf, "\t\t\tt.Errorf(\"expected %s message but did not receive it; got: %%v\", receivedTypes)\n", srv.TypeName)
			buf.WriteString("\t\t}\n")
		}
	} else {
		// Bidirectional: collect initial FromServer messages, send FromClient,
		// collect remaining FromServer messages.
		// [L1] CRITICAL: After sub.Publish, skip echoed FromClient messages.

		// We just collect messages in a loop, interleaving sends when we see
		// the right trigger messages. Simpler: collect all, then send mid-stream,
		// collect rest.

		// First, collect initial messages until we see a message that indicates
		// the server is ready for client input (or just wait a bit).
		// For simplicity, we wait for at least 1 server message, then send the
		// client messages, then collect the rest.

		buf.WriteString("\t\t// Bidirectional channel: collect initial messages, send client response, collect rest.\n")
		buf.WriteString("\t\t// Wait for at least one server message before sending client messages.\n")
		buf.WriteString("\tinitialLoop:\n")
		buf.WriteString("\t\tfor {\n")
		buf.WriteString("\t\t\tselect {\n")
		buf.WriteString("\t\t\tcase <-deadline:\n")
		buf.WriteString("\t\t\t\tt.Fatalf(\"timed out waiting for initial server message\")\n")
		buf.WriteString("\t\t\tcase data := <-pubCh:\n")
		buf.WriteString("\t\t\t\tvar env e2eEnvelope\n")
		buf.WriteString("\t\t\t\tif err := json.Unmarshal(data, &env); err != nil {\n")
		buf.WriteString("\t\t\t\t\tcontinue\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t\tif isFromClientType(env.Type) {\n")
		buf.WriteString("\t\t\t\t\tcontinue\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t\treceived = append(received, env)\n")
		buf.WriteString("\t\t\t\tbreak initialLoop\n")
		buf.WriteString("\t\t\t}\n")
		buf.WriteString("\t\t}\n")
		buf.WriteString("\n")

		// Send mid-stream client messages via sub.Publish
		buf.WriteString("\t\t// Send mid-stream client messages\n")
		for _, mid := range fromClientMidStream {
			midType := ch.PackageName + "." + mid.TypeName
			fmt.Fprintf(buf, "\t\t{\n")
			fmt.Fprintf(buf, "\t\t\tmsg := %s{", midType)
			writeE2ETestFieldValues(buf, mid.Fields)
			buf.WriteString("}\n")
			buf.WriteString("\t\t\tmsgData, _ := json.Marshal(msg)\n")
			fmt.Fprintf(buf, "\t\t\tenv := e2eEnvelope{Type: %q, Data: msgData}\n", mid.TypeName)
			buf.WriteString("\t\t\tenvData, _ := json.Marshal(env)\n")
			buf.WriteString("\t\t\tif _, err := sub.Publish(context.Background(), envData); err != nil {\n")
			fmt.Fprintf(buf, "\t\t\t\tt.Fatalf(\"publish %s: %%v\", err)\n", mid.TypeName)
			buf.WriteString("\t\t\t}\n")
			buf.WriteString("\t\t}\n")
		}
		buf.WriteString("\n")

		// Collect remaining messages
		// [L1]: Skip echoed FromClient messages
		totalExpected := len(fromServerMsgs)
		fmt.Fprintf(buf, "\t\t// Collect remaining FromServer messages (expected total: %d)\n", totalExpected)
		fmt.Fprintf(buf, "\tcollectLoop:\n")
		fmt.Fprintf(buf, "\t\tfor len(received) < %d {\n", totalExpected)
		buf.WriteString("\t\t\tselect {\n")
		buf.WriteString("\t\t\tcase <-deadline:\n")
		fmt.Fprintf(buf, "\t\t\t\tt.Fatalf(\"timed out waiting for remaining messages; received %%d of %d: %%+v\", len(received), received)\n", totalExpected)
		buf.WriteString("\t\t\tcase data := <-pubCh:\n")
		buf.WriteString("\t\t\t\tvar env e2eEnvelope\n")
		buf.WriteString("\t\t\t\tif err := json.Unmarshal(data, &env); err != nil {\n")
		buf.WriteString("\t\t\t\t\tcontinue\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t\t// [L1] CRITICAL: Skip echoed FromClient messages\n")
		buf.WriteString("\t\t\t\tif isFromClientType(env.Type) {\n")
		buf.WriteString("\t\t\t\t\tcontinue\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t\treceived = append(received, env)\n")
		fmt.Fprintf(buf, "\t\t\t\tif len(received) >= %d {\n", totalExpected)
		buf.WriteString("\t\t\t\t\tbreak collectLoop\n")
		buf.WriteString("\t\t\t\t}\n")
		buf.WriteString("\t\t\t}\n")
		buf.WriteString("\t\t}\n")
		buf.WriteString("\n")

		// Verify expected types
		buf.WriteString("\t\t// Verify expected FromServer messages\n")
		buf.WriteString("\t\treceivedTypes := make(map[string]int)\n")
		buf.WriteString("\t\tfor _, env := range received {\n")
		buf.WriteString("\t\t\treceivedTypes[env.Type]++\n")
		buf.WriteString("\t\t}\n")
		for _, srv := range fromServerMsgs {
			fmt.Fprintf(buf, "\t\tif receivedTypes[%q] == 0 {\n", srv.TypeName)
			fmt.Fprintf(buf, "\t\t\tt.Errorf(\"expected %s message but did not receive it; got: %%v\", receivedTypes)\n", srv.TypeName)
			buf.WriteString("\t\t}\n")
		}
	}

	// Verify job status via GET /channels/jobs/:id
	buf.WriteString("\n")
	buf.WriteString("\t\t// Verify job result via API\n")
	buf.WriteString("\t\tjobURL := fmt.Sprintf(\"%s/channels/jobs/%s\", baseURL, jobID)\n")
	buf.WriteString("\t\tjobResp, err := http.Get(jobURL)\n")
	buf.WriteString("\t\tif err != nil {\n")
	buf.WriteString("\t\t\tt.Logf(\"could not fetch job status (non-fatal): %v\", err)\n")
	buf.WriteString("\t\t} else {\n")
	buf.WriteString("\t\t\tdefer jobResp.Body.Close()\n")
	buf.WriteString("\t\t\tjobBody, _ := io.ReadAll(jobResp.Body)\n")
	buf.WriteString("\t\t\tt.Logf(\"job status: %s\", string(jobBody))\n")
	buf.WriteString("\t\t}\n")

	buf.WriteString("\t})\n\n")
}

// writeE2ETestFieldValues writes test field initializers for E2E dispatch payloads.
func writeE2ETestFieldValues(buf *bytes.Buffer, fields []codegen.SerializedFieldInfo) {
	if len(fields) == 0 {
		return
	}
	for i, f := range fields {
		if i > 0 {
			buf.WriteString(", ")
		}
		fmt.Fprintf(buf, "%s: %s", f.Name, e2eTestValue(f.Type))
	}
}

// e2eTestValue returns a suitable test value for E2E tests.
func e2eTestValue(goType string) string {
	switch goType {
	case "string":
		return `"e2e-test"`
	case "int", "int8", "int16", "int32", "int64":
		return "1"
	case "uint", "uint8", "uint16", "uint32", "uint64":
		return "1"
	case "float32", "float64":
		return "1.0"
	case "bool":
		return "true"
	default:
		if strings.HasPrefix(goType, "[]") {
			return "nil"
		}
		if strings.HasPrefix(goType, "*") {
			return "nil"
		}
		if strings.HasPrefix(goType, "map[") {
			return "nil"
		}
		return `"e2e-test"`
	}
}
